  };
}

{ ... }:
{
  documentation.enable = false;

  nix.settings = {
    experimental-features = [ "nix-command" "flakes" ];
    trusted-users = [ "root" "@wheel" ];
  };

  programs.ssh.extraConfig = ''
    Host github.com
      IdentityFile /etc/ssh/ssh_host_ed25519_key
      IdentitiesOnly yes
  '';
}

{ pkgs, ... }:
{
  environment.systemPackages = with pkgs; [
    neovim
    k3s
    cifs-utils
    nfs-utils
    git
    age
    htop
    tmux
    tree
  ];
}

{ meta, ... }:
{
  users.users.${meta.hostname} = {
    isNormalUser = true;
    extraGroups = [ "wheel" ];
  };

  security.sudo.wheelNeedsPassword = false;

  services.openssh.enable = true;
}

{ pkgs, ... }:
{
  systemd.services.cloud-keys = {
    description = "Inject operator SSH keys from Hetzner metadata";
    wantedBy = [ "multi-user.target" ];
    wants = [ "network-online.target" ];
    after = [ "network-online.target" ];
    serviceConfig = {
      Type = "oneshot";
      RemainAfterExit = true;
      Restart = "on-failure";
      RestartSec = "5";
      StartLimitBurst = 10;
      StartLimitIntervalSec = 600;
    };
    script = ''
      set -Eeuo pipefail

      install -m 700 -d /root/.ssh
      touch /root/.ssh/authorized_keys
      chmod 600 /root/.ssh/authorized_keys

      RAW=$(mktemp)
      PARSED=$(mktemp)
      trap 'rm -f "$RAW" "$PARSED"' EXIT

      HTTP_CODE=$(${pkgs.curl}/bin/curl -sS -o "$RAW" \
        -w '%{http_code}' \
        --connect-timeout 5 --max-time 10 --retry 3 --retry-delay 2 \
        http://169.254.169.254/hetzner/v1/metadata)

      RAW_BYTES=$(${pkgs.coreutils}/bin/wc -c < "$RAW")
      echo "cloud-keys: metadata http_code=$HTTP_CODE bytes=$RAW_BYTES"

      if [ "$HTTP_CODE" != "200" ]; then
        echo "cloud-keys: metadata fetch failed" >&2
        exit 1
      fi

      ${pkgs.gnugrep}/bin/grep -oE '(ssh-rsa|ssh-ed25519|ecdsa-sha2-nistp[0-9]+) [A-Za-z0-9+/=]+( [^[:space:]]+)?' "$RAW" \
        > "$PARSED" || true

      PARSED_LINES=$(${pkgs.coreutils}/bin/wc -l < "$PARSED")
      echo "cloud-keys: parsed_keys=$PARSED_LINES"

      while IFS= read -r KEY; do
        FP=$(echo "$KEY" | ${pkgs.openssh}/bin/ssh-keygen -lf - 2>/dev/null || echo "fingerprint-failed")
        echo "cloud-keys: fingerprint $FP"
      done < "$PARSED"

      if [ "$PARSED_LINES" -lt 1 ]; then
        echo "cloud-keys: no keys in metadata response" >&2
        exit 1
      fi

      cat "$PARSED" >> /root/.ssh/authorized_keys
      ${pkgs.coreutils}/bin/sort -u /root/.ssh/authorized_keys -o /root/.ssh/authorized_keys

      FINAL_LINES=$(${pkgs.coreutils}/bin/wc -l < /root/.ssh/authorized_keys)
      echo "cloud-keys: authorized_keys lines=$FINAL_LINES"
    '';
  };
}

{ lib, meta, ... }:
{
  imports = [ ./common.nix ];

  services.k3s = {
    enable = true;
    role = "agent";
    serverAddr = lib.mkDefault "https://10.0.0.10:6443";
    tokenFile = "/etc/k3s/token";
    extraFlags = [ "--node-label=node.kubernetes.io/role=worker" ];
  };

  boot.kernel.sysctl."net.bridge.bridge-nf-call-iptables" = lib.mkDefault 1;

  networking.firewall.allowedTCPPorts = [ 10250 ];
  networking.firewall.allowedUDPPorts = [ 8472 ];
}

{ ... }:
{
  systemd.services.k3s = {
    wants = [ "network-online.target" ];
    after = [ "network-online.target" ];
  };
}

{ privateIp, ... }:
{
  services.k3s.extraFlags = [
    "--flannel-iface=enp7s0"
    "--node-ip=${privateIp}"
  ];
}

{ ... }:
{
}

{ config, pkgs, meta, ... }:
{
  services.openiscsi = {
    enable = true;
    name = "iqn.2016-04.com.open-iscsi:${meta.hostname}";
  };

  systemd.tmpfiles.rules = [
    "L+ /usr/local/bin - - - - /run/current-system/sw/bin/"
  ];
}

{ pkgs, ... }:
{
  systemd.services.rollback-gate = {
    description = "NixOS dead-man's switch: revert unless a staged repair was committed in time";

    serviceConfig = {
      Type = "oneshot";
      ExecStart = pkgs.writeShellScript "rollback-gate-expire" ''
        echo "rollback-gate: confirmation deadline expired without commit; reverting to boot default" >&2
        exit 1
      '';
      FailureAction = "reboot-force";
    };
  };

  systemd.timers.rollback-gate = {
    description = "Dead-man's switch deadline; armed at staging, disarmed on commit";
    timerConfig = {
      OnActiveSec = "180s";
      Unit = "rollback-gate.service";
    };
  };
}

{ config, pkgs, lib, ... }:
let
  cfg = config.services.vigilAutoReconciler;
in
{
  options.services.vigilAutoReconciler = {
    enable = lib.mkEnableOption "vigil NixOS auto-reconciler";
    branch = lib.mkOption {
      type = lib.types.str;
      description = "Git branch to track for NixOS config reconciliation.";
    };
  };

  config = lib.mkIf cfg.enable {
    systemd.services.vigil-auto-reconcile = {
      description = "Vigil NixOS auto-reconciler";
      path = [ pkgs.git pkgs.hostname pkgs.nixos-rebuild pkgs.util-linux ];
      serviceConfig = {
        Type = "oneshot";
        RemainAfterExit = false;
        ExecStart = pkgs.writeShellScript "vigil-auto-reconcile" ''
          set -euo pipefail
          BRANCH="${cfg.branch}"
          STATE_FILE="/var/lib/vigil-reconciler/last-sha"
          mkdir -p "$(dirname "$STATE_FILE")"
          git -C /opt/nixos-config fetch origin
          NEW=$(git -C /opt/nixos-config rev-parse "origin/$BRANCH")
          git -C /opt/nixos-config reset --hard "origin/$BRANCH"
          OLD=$(cat "$STATE_FILE" 2>/dev/null || echo "")
          if [ "$NEW" != "$OLD" ]; then
            flock /var/lock/vigil-nixos-rebuild nixos-rebuild switch --flake "/opt/nixos-config#$(hostname)"
            echo "$NEW" > "$STATE_FILE"
          fi
        '';
      };
    };

    systemd.timers.vigil-auto-reconcile = {
      description = "Timer for vigil NixOS auto-reconciler";
      wantedBy = [ "multi-user.target" ];
      timerConfig = {
        OnBootSec = "300s";
        OnUnitActiveSec = "300s";
        Unit = "vigil-auto-reconcile.service";
      };
    };
  };
}

